map "http://ahdbservices.it/fhir/StructureMap/QuestionnaireToQuestionnaireResponse" = "QuestionnaireToQuestionnaireResponse"

uses "http://hl7.org/fhir/StructureDefinition/Patient" alias Patient as target
uses "http://hl7.org/fhir/StructureDefinition/QuestionnaireResponse" alias QuestionnaireResponse as target
uses "http://ahdbservices.it/fhir/StructureDefinition/QuestionnaireInput" alias QuestionnaireInput as source

group QuestionnaireToQuestionnaireResponse(
  source rer : QuestionnaireInput,
  source patient : Patient,
  source encounter : Encounter,
  source practitioner : Practitioner,
  target qr : QuestionnaireResponse
) {
    rer -> qr.status = 'completed' "MDSUPDRS status";
    rer -> qr.questionnaire = "Questionnaire?name=MDSUPDRS" "MDSUPDRS Questionnaire uri";

    patient -> qr.subject = create('Reference') as subj_r then {
        patient.id as p_id -> subj_r.reference = append("urn:uuid:", p_id) "reference";
    } "QuestionnaireInput Questionnaire subject";

    encounter -> qr.encounter = create('Reference') as enc_r then {
        encounter.id as enc_id -> enc_r.reference = append("urn:uuid:", enc_id) "reference";
    } "QuestionnaireInput Questionnaire Encounter";

    practitioner -> qr.author = create('Reference') as prac_r then {
        practitioner.id as prac_id -> prac_r.reference = append("urn:uuid:", prac_id) "reference";
    } "QuestionnaireInput Questionnaire Practitioner";

    rer.mds_3_1 as r ->
        qr.item as i,
        i.linkId = "mds_3_1",
        i.answer as a,
        a.value = create("Quantity") as vq,
        vq.value = r,
        vq.system = "http://unitsofmeasure.org",
        vq.code = "{score}",
        vq.unit = "{score}";

